13: func Convert_V1_to_V0(in *dashv1.Dashboard, out *dashv0.Dashboard, scope conversion.Scope) error {
14: 	out.ObjectMeta = in.ObjectMeta
15: 
16: 	out.Spec.Object = in.Spec.Object
17: 
18: 	out.Status = dashv0.DashboardStatus{
19: 		Conversion: &dashv0.DashboardConversionStatus{
20: 			StoredVersion: ptr.To(dashv1.VERSION),
21: 		},
22: 	}
23: 
24: 	return nil
25: }
26: 
27: func Convert_V1_to_V2alpha1(in *dashv1.Dashboard, out *dashv2alpha1.Dashboard, scope conversion.Scope) error {
28: 	out.ObjectMeta = in.ObjectMeta
29: 
30: 	// TODO (@radiohead): implement V1 to V2 conversion
31: 	// This is the bare minimum conversion that is needed to make the dashboard servable.
32: 
33: 	if v, ok := in.Spec.Object["title"]; ok {
34: 		if title, ok := v.(string); ok {
35: 			out.Spec.Title = title
36: 		}
37: 	}
38: 
